use std::collections::VecDeque;

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    if n == 0 {
        return -1;
    }
    let max_edge = edges.iter().map(|e| e[2]).max().unwrap_or(0);
    let mut low = 0;
    let mut high = max_edge + 1;

    while low < high {
        let mid = (low + high) / 2;
        if check(mid, &edges, &online, k, n) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }

    let ans = low - 1;
    if ans < 0 {
        -1
    } else {
        ans
    }
}

fn check(x: i64, edges: &Vec<Vec<i64>>, online: &Vec<bool>, k: i64, n: usize) -> bool {
    let mut dp = vec![i64::MAX; n];
    dp[0] = 0;

    let mut graph: Vec<Vec<(usize, i64)>> = vec![vec![]; n];
    let mut in_degree = vec![0; n];

    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let c = edge[2];

        if v == 0 || u == n-1 {
            continue;
        }
        if !online[u] || !online[v] {
            continue;
        }
        if c < x {
            continue;
        }

        graph[u].push((v, c));
        in_degree[v] += 1;
    }

    let mut queue = VecDeque::new();
    if in_degree[0] == 0 {
        queue.push_back(0);
    } else {
        return false;
    }

    while let Some(u) = queue.pop_front() {
        for &(v, cost) in &graph[u] {
            if dp[u] != i64::MAX && cost <= k && dp[u] <= k - cost {
                let new_cost = dp[u] + cost;
                if new_cost < dp[v] {
                    dp[v] = new_cost;
                }
            }
            in_degree[v] -= 1;
            if in_degree[v] == 0 {
                queue.push_back(v);
            }
        }
    }

    dp[n-1] <= k
}
```

