fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    let last_node = n - 1;

    let mut base_graph: Vec<Vec<(usize, i64)>> = vec![Vec::new(); n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let cost = edge[2];
        if v == 0 || u == last_node {
            continue;
        }
        if online[u] && online[v] {
            base_graph[u].push((v, cost));
        }
    }

    let mut reachable = vec![false; n];
    let mut queue = std::collections::VecDeque::new();
    reachable[0] = true;
    queue.push_back(0);
    while let Some(u) = queue.pop_front() {
        for &(v, _) in &base_graph[u] {
            if !reachable[v] {
                reachable[v] = true;
                queue.push_back(v);
            }
        }
    }

    if !reachable[last_node] {
        return -1;
    }

    let mut in_degree = vec![0; n];
    for u in 0..n {
        if reachable[u] {
            for &(v, _) in &base_graph[u] {
                if reachable[v] {
                    in_degree[v] += 1;
                }
            }
        }
    }

    let mut topo_order = Vec::new();
    let mut queue = std::collections::VecDeque::new();
    for u in 0..n {
        if reachable[u] && in_degree[u] == 0 {
            queue.push_back(u);
        }
    }
    while let Some(u) = queue.pop_front() {
        topo_order.push(u);
        for &(v, _) in &base_graph[u] {
            if reachable[v] {
                in_degree[v] -= 1;
                if in_degree[v] == 0 {
                    queue.push_back(v);
                }
            }
        }
    }

    let max_candidate = edges.iter().map(|e| e[2]).max().unwrap_or(0);
    let inf = i64::MAX;

    let mut lo = 0;
    let mut hi = max_candidate;
    let mut ans = -1;

    while lo <= hi {
        let mid = (lo + hi) / 2;
        if check_candidate(mid, &base_graph, &topo_order, n, k, inf) {
            ans = mid;
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }

    ans
}

fn check_candidate(x: i64, base_graph: &[Vec<(usize, i64)>], topo_order: &[usize], n: usize, k: i64, inf: i64) -> bool {
    let mut dp = vec![inf; n];
    dp[0] = 0;
    for &u in topo_order {
        if dp[u] == inf {
            continue;
        }
        for &(v, cost) in &base_graph[u] {
            if cost >= x {
                let new_cost = dp[u].saturating_add(cost);
                if new_cost < dp[v] {
                    dp[v] = new_cost;
                }
            }
        }
    }
    dp[n - 1] <= k
}
```

