```rust
use std::collections::VecDeque;

const BIG: i64 = 1_000_000_000_000_000_000;

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    let mut adj = vec![vec![]; n];
    for e in &edges {
        let u = e[0] as usize;
        let v = e[1] as usize;
        let cost = e[2];
        adj[u].push((v, cost));
    }

    let mut in_degree = vec![0; n];
    for u in 0..n {
        for (v, _) in &adj[u] {
            in_degree[*v] += 1;
        }
    }

    let mut q = VecDeque::new();
    for i in 0..n {
        if in_degree[i] == 0 {
            q.push_back(i);
        }
    }
    let mut topo = Vec::with_capacity(n);
    while let Some(u) = q.pop_front() {
        topo.push(u);
        for (v, _) in &adj[u] {
            in_degree[*v] -= 1;
            if in_degree[*v] == 0 {
                q.push_back(*v);
            }
        }
    }

    let max_edge = edges.iter().map(|e| e[2]).max().unwrap_or(0);
    let mut lo = 0;
    let mut hi = max_edge + 1;

    let mut dp = vec![BIG; n];

    while lo < hi {
        let mid = (lo + hi) / 2;
        dp.fill(BIG);
        dp[0] = 0;

        for &u in &topo {
            if !online[u] {
                continue;
            }
            if dp[u] == BIG {
                continue;
            }
            for &(v, c) in &adj[u] {
                if !online[v] || c < mid {
                    continue;
                }
                let new_cost = dp[u] + c;
                if new_cost < dp[v] {
                    dp[v] = new_cost;
                }
            }
        }

        if dp[n-1] <= k {
            lo = mid + 1;
        } else {
            hi = mid;
        }
    }

    if lo == 0 {
        -1
    } else {
        lo - 1
    }
}
```

### Explanation
1. **Graph Representation**: The adjacency list `adj` is built from the input edges, storing each edge's destination and cost.
2. **Topological Sorting**: The topological order `topo` is computed using Kahn's algorithm, which processes nodes by repeatedly removing nodes with no incoming edges.
3. **Binary Search Setup**: The binary search range is set from 0 to the maximum edge cost plus one. This range covers all possible values for the minimum edge cost in any valid path.
4. **Candidate Validation**:
   - **DP Initialization**: The DP array is initialized to a large value (BIG) to represent initially unreachable nodes, with \( dp[0] = 0 \) (the start node).
   - **Processing Nodes**: Nodes are processed in topological order. For each online node, outgoing edges that meet the cost threshold \( mid \) are considered to update the DP values for destination nodes.
5. **Binary Search Adjustment**: After processing all nodes for a candidate \( mid \), if the end node \( n-1 \) is reachable within cost \( k \), the search continues for a higher \( mid \); otherwise, it searches lower.
6. **Result Extraction**: The binary search concludes with the highest \( mid \) for which a valid path exists. If no path exists (\( lo = 0 \)), -1 is returned; otherwise, \( lo - 1 \) is the result. 

This approach efficiently narrows down the possible path scores using binary search and validates candidates with a topological traversal and dynamic programming, leveraging the DAG structure for optimal performance.
